  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000005', 'Protection intempéries', 'Mesures chaleur (>30°) / Froid', 'OTConst 10', 'Climat', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000006', 'Exposition sonore', 'Protection dès 85 dB(A)', 'OTConst 11', 'Bruit', false, true),
