  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000006', 'Aspiration à la source', 'Aspi HEPA pour quartz/béton', 'OTConst 13', 'Poussières', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000006', 'Respect rapport polluants', 'Arrêt si matériau suspect', 'OTConst 14', 'Amiante', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Câbles mobiles', 'Pas de gaines nues, surélevés', 'OTConst 70', 'Electricité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Fermeture armoires élec', 'Verrouillées et étanches', 'OTConst 71', 'Tableaux', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Disjoncteurs DDR (FI)', '30mA obligatoire pour prises', 'OTConst 72', 'Prises', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Niveau d''éclairement', 'Visibilité parfaite des postes', 'OTConst 73', 'Eclairage', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Dispositifs de sécurité', 'Carters de protection en place', 'OTConst 74', 'Machines', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Boutons arrêt urgence', 'Accessibles et fonctionnels', 'OTConst 75', 'Arrêt urgence', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Protection lame scie', 'Couteau diviseur présent', 'OTConst 76', 'Scies', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Permis de conduite (M1-M7)', 'Permis dispo sur l''opérateur', 'OTConst 77', 'Engins', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Carnet entretien engins', 'Contrôles annuels à jour', 'OTConst 78', 'Maintenance', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Avertisseurs recul', 'Fonctionnels (Bip-Bip)', 'OTConst 79', 'Signaux', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Rétroviseurs/Caméras', 'Vision panoramique dégagée', 'OTConst 80', 'Visibilité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Interdiction transport gens', 'Personne dans le godet', 'OTConst 81', 'Transport', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Stabilisateurs pompes', 'Plaques de répartition au sol', 'OTConst 82', 'Stabilité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Réseaux enterrés', 'Plans SIG présents sur site', 'OTConst 83', 'Canalisations', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Distances sécurité aérienne', 'Min. 5m des lignes HT', 'OTConst 84', 'Lignes HT', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Autorisation de tir', 'Boutefeu diplômé uniquement', 'OTConst 85', 'Minage', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Projections minage', 'Pare-éclats obligatoires', 'OTConst 86', 'Débris', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Consignation brûleurs', 'Système LOTO (Cadenas)', 'OTConst 111', 'Thermique', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Gaz nocifs chaudières', 'Mesure préalable avant entrée', 'OTConst 112', 'Gaz', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Echelles cheminées', 'Dispositif antichute fixe', 'OTConst 113', 'Ascensions', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000006', 'Lignes survol route', 'Hauteur min. 4.5m', 'RPAC 08', 'Electricité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Lavage des roues', 'Pas de boue sur domaine public', 'RPAC 09', 'Propreté', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Amarrage matériaux', 'Contre envol par vent fort', 'RPAC 10', 'Intempéries', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000008', 'Surveillance post-soudure', 'Ronde 1h après fin travail', 'RPAC 11', 'Travaux chaud', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Signalement des défauts', 'Ouvriers formés à avertir', 'RPAC 12', 'Défauts', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Traçabilité signalements', 'Registre sécurité à jour', 'RPAC 13', 'Signalement', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Grilles d''égout', 'Protection contre laitance', 'RPAC 14', 'Eaux', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000008', 'Tri des déchets', 'Séparation bois/fer/béton', 'RPAC 15', 'Déblais', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Objets saillants', 'Bouchons sur fers à béton', 'RPAC 18', 'Public', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Maintien en état', 'Pas de stockage sur auvent', 'RPAC 19', 'Auvents', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Usage nacelle', 'Certificat formation plateforme', 'RPAC 20', 'Nacelles', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Engins routiers', 'Plaques immatriculation', 'RPAC 21', 'Autorisation', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Accès toit', 'Echelles fixées mécaniquement', 'RPAC 22', 'Toit', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Etat clôture', 'Pas de panneaux déboîtés', 'RPAC 25', 'Clôture', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Poussières', 'Arrosage zone démolition', 'RPAC 26', 'Public', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000009', 'Les projets, plans d''exécution et installations doivent être étudiés pour permettre l''application des mesures de sécurité prescrites. Un plan détaillé (PPSPS) de la sécurité et des premiers secours doit exister avant le début des travaux.', NULL, 'RPAC Art. 3 / OTConst Art. 3, 4', 'Sécurité Globale (PPSPS)', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000010', 'L''organe de contrôle de la commune doit être convoqué et avisé sur place au moins 10 jours avant l''ouverture du chantier ou le montage de grues et d''échafaudages (notamment pour les travaux en bordure du domaine public). Un plan d''installation de chantier doit être présenté.', NULL, 'RPAC Art. 5 / Phase 1 - 1.1.7', 'Avis aux Autorités (Communes)', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000011', 'Les travaux spéciaux doivent être annoncés à la SUVA au moins 14 jours avant leur exécution (ex: travaux souterrains, désamiantage, abattage de roche > 5000 m³).', NULL, 'OTConst Art. 86, 87, 102', 'Avis aux Autorités (SUVA)', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000012', 'Le chantier doit être délimité par des palissades, treillis ou barrières pour empêcher l''accès au public. Prévoir la protection du public par des tunnels, auvents, ou déviations du cheminement.', NULL, 'RPAC Art. 7, 9 / Phase 1 - 1.1.1', 'Confinement & Délimitation', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000013', 'Pour empêcher la chute de matériaux (notamment lors de démolitions), il faut exiger l''installation d''échafaudages, d''auvents, de tapis, de parois renforcées, et un démontage niveau par niveau. Pour les constructions, exiger le montage simultané des échafaudages avec la progression de l''élévation, accompagnés de filets.', NULL, 'RPAC Art. 7, 9, 15, 17 / OTConst Art. 18 / Phase 1 - 1.1.2, 1.1.4', 'Chutes de matériaux sur domaine public', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000014', 'Pour éviter de rendre les routes glissantes ou sales, il faut prévoir un décrotteur (lave-roues) à la sortie du chantier ou la construction d''une piste propre pour les camions de terrassement.', NULL, 'RPAC Art. 9 / Phase 1 - 1.1.3', 'Propreté des voies publiques', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000015', 'Préciser dans les directives que les grues ne doivent pas transiter avec des charges au-dessus du public ou à proximité de lignes électriques. Envisager et exiger la pose de limiteurs d''évolution (électriques/mécaniques) sur les grues.', NULL, 'RPAC Art. 26 / Ord. Grues Art. 4 / Phase 1 - 1.1.5', 'Survol des Grues & Lignes électriques', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000016', 'Lors du montage/démontage d''échafaudages ou réfection de façades sur le domaine public, exiger que les échafaudages soient posés sur tunnel, munis de filets et d''auvents pour que le public transite sans danger. Les cheminements doivent tenir compte des personnes handicapées.', NULL, 'RPAC Art. 17, 18, 19, 20 / Phase 1 - 1.1.6', 'Passage sécurisé du Public', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000017', 'Si la présence de substances dangereuses (amiante, PCB) est suspectée lors de rénovations ou démolitions, l''employeur doit identifier les dangers avant le début des travaux et planifier les mesures nécessaires.', NULL, 'OTConst Art. 3, 32 / RPAC Art. 11', 'Diagnostic Polluants (Amiante/PCB)', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000018', 'Avant de débuter, déterminer s''il existe des réseaux dangereux (électricité, gaz, puits) dans la zone de travail et fixer les mesures de sécurité avec le propriétaire des réseaux.', NULL, 'OTConst Art. 30', 'Installations souterraines et existantes', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000019', 'Rappeler aux requérants les exigences relatives aux barres de sécurité et ancrages de toits qui doivent être installés de manière permanente pour l''entretien futur.', NULL, 'RPAC Art. 23, 24 / Phase 1 - 1.1.8', 'Sécurité permanente en Toiture', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000020', 'Le chantier doit être clôturé pour empêcher l''accès au public (sauf dispense). La résistance de la clôture doit être adaptée et l''interdiction de pénétrer signalée. Si la clôture prévient un risque de chute, les normes des garde-corps s''appliquent.', NULL, 'RPAC Art. 7 / Phase 2', 'Clôtures et Sécurité du public', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000021', 'Les passages publics aux abords du chantier doivent être aménagés, maintenus ou déplacés en tenant compte spécifiquement des besoins des personnes handicapées physiques ou de la vue.', NULL, 'RPAC Art. 7 / Phase 2', 'Cheminements & Accessibilité', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000022', 'Toutes les précautions doivent être prises pour éviter de souiller les chaussées publiques. L''organe de contrôle valide la propreté des accès et peut exiger l''installation d''un dispositif de nettoyage des véhicules (décrotteur) sur le chantier.', NULL, 'RPAC Art. 9 / Phase 2', 'Propreté de la chaussée (Décrotteur)', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000023', 'Vérification sur place de l''emplacement de la grue : la visibilité doit être assurée, et la flèche doit pouvoir être mise en giration libre (sans charge) lorsqu''elle n''est pas utilisée. Un espace libre de 8 m au moins doit être maintenu au-dessus des routes ou accès publics.', NULL, 'RPAC Art. 26 / Phase 2', 'Implantation de la Grue', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000024', 'Lors de la séance sur place, il faut analyser le mode de démolition, évaluer les risques pour les bâtiments voisins, et valider la résistance des dalles avant le début de l''intervention.', NULL, 'Phase 2', 'Risques de Démolition & Dalles', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000025', 'Validation de la coupure et de la protection des réseaux existants (électricité, gaz, eau) avant le démarrage effectif des travaux de terrassement ou de démolition.', NULL, 'Phase 2 / RPAC Art. 11', 'Coupure des réseaux & Installations', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000026', 'Sur les chantiers de rénovation ou démolition, vérification sur place de la recherche de produits dangereux (amiante) et des précautions particulières mises en œuvre selon les diagnostics préalables.', NULL, 'Phase 2 / RPAC Art. 11', 'Polluants (Amiante sur site)', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000027', 'Validation de l''emplacement de la centrale à béton et de son bac de décantation pour la protection des eaux. Mise en place du tri des déchets selon les normes SIA.', NULL, 'Phase 2 / Guide SIA 430/431', 'Environnement (Centrale à béton & Déchets)', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000028', 'L''éclairage du chantier et de ses abords doit être vérifié et jugé suffisant pour prévenir tout risque d''accident, particulièrement aux accès.', NULL, 'RPAC Art. 7', 'Éclairage du chantier', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000029', 'L''organe de contrôle doit être avisé, au moins 10 jours à l''avance, du montage d''une grue sur le chantier.', NULL, 'RPAC Art. 5', 'Avis de montage (Commune)', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000030', 'Un profil d''espace libre de 8 m au moins doit être maintenu au-dessus d''une route ou d''un accès public. La flèche doit pouvoir demeurer en girouette à 2 m des obstacles.', NULL, 'RPAC Art. 26', 'Implantation et Espace libre (Pré-montage)', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000031', 'La manutention de charges est strictement interdite sans une protection spéciale au-dessus d''une route ou d''endroits accessibles au public. L''organe de contrôle peut exiger un système limitant ou interdisant l''évolution des charges dans ces zones.', NULL, 'RPAC Art. 26 / Phase 3', 'Protection du public et Survol', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000032', 'Lorsque l''engin n''est pas utilisé (hors des heures de travail), la flèche doit impérativement être mise en giration libre, sans aucune charge accrochée au crochet.', NULL, 'RPAC Art. 26', 'Mise en Giration libre (Girouette)', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000033', 'Après le montage, des tests de fonctionnement doivent être réalisés avec les charges maximums en pied et en bout de flèche. L''horizontalité des fondations et les limiteurs d''évolution doivent être vérifiés. L''autorité peut exiger ces essais de stabilité avant utilisation.', NULL, 'Phase 3 / Ord. grues Art. 4-6 / RPAC Art. 5', 'Tests en charge et Fondations (Post-montage)', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000034', 'L''utilisation et la conduite des grues sont soumises à l''Ordonnance fédérale. Le conducteur doit posséder un permis reconnu ou une attestation provisoire pour manœuvrer l''engin.', NULL, 'RPAC Art. 25', 'Habilitation du Grutier', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000035', 'Sont réservées les autorisations spéciales de l''Office fédéral de l''aviation civile (OFAC) pour les grues > 60 m en zone fortement peuplée, ou > 25 m dans les autres régions ou dans les zones de sécurité d''un aérodrome.', NULL, 'RPAC Art. 26', 'Autorisations Spéciales (Hauteur / OFAC)', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000036', 'Les travailleurs exécutant des tâches à proximité des grues doivent obligatoirement porter un casque de protection.', NULL, 'OTConst Art. 6', 'Sécurité aux abords de la grue (EPI)', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000037', 'Les échafaudages ne peuvent être construits, démontés ou modifiés que sous la direction d''une personne compétente et selon les prescriptions du fabricant. L''abattage et le démontage brutal d''échafaudages sont strictement interdits.', NULL, 'RPAC Art. 17 / OTConst Art. 60', 'Direction du montage et Démontage', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000038', 'Un cheminement sûr pour les piétons et les personnes handicapées doit être garanti (tunnel étanche de 30 cm du trottoir minimum). Les passages couverts doivent éviter l''infiltration de poussières, boues ou liquides. Des lattes inférieures détectables pour les aveugles doivent être posées.', NULL, 'RPAC Art. 7, 18 / Phase 4', 'Protection du public (Tunnels et Cheminements)', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000039', 'Des auvents inclinés à 45° et mesurant au moins 1,50 m de hauteur doivent être installés au droit des parties dominant la rue. Le plancher doit être jointif (aucun vide avec la façade) et la partie inférieure de l''auvent doit se situer à 4,50 m minimum au-dessus de la chaussée.', NULL, 'RPAC Art. 19 / Phase 4', 'Auvents de protection (Plateaux de garde)', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000040', 'L''échafaudage doit être ancré au bâtiment pour résister aux efforts de traction et de compression (ex: vent, neige). L''organe de contrôle vérifie le nombre d''ancrages, avec une règle indicative d''au moins 1 ancrage par 25 m².', NULL, 'OTConst Art. 47, 51 / Phase 4', 'Ancrages et Stabilité', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000041', 'L''échafaudage doit respecter des largeurs et charges minimales selon les travaux : 60 cm de large et 2.0 kN/m² pour les travaux légers (peinture) ; 90 cm et 3.0 kN/m² pour les travaux lourds (maçonnerie).', NULL, 'OTConst Art. 55', 'Dimensions et Capacité de charge', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000042', 'La charge utile de l''échafaudage de service doit être indiquée de manière bien visible sur un panneau apposé à chaque accès. Les zones dont l''usage n''a pas été autorisé doivent être bloquées techniquement.', NULL, 'OTConst Art. 62, 63', 'Signalisation de la charge utile', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000043', 'La distance entre le platelage de l''échafaudage et la façade ne doit, dans aucune phase de travail, dépasser 30 cm. Si ce n''est pas possible, des mesures complémentaires (ex: garde-corps intérieur) doivent être prises pour éviter les chutes.', NULL, 'OTConst Art. 57', 'Distance à la façade (Platelage)', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000044', 'L''employeur doit veiller à ce que l''échafaudage de service, les filets de sécurité et les échafaudages de retenue soient contrôlés visuellement chaque jour. S''ils présentent des défauts, leur utilisation est strictement interdite.', NULL, 'OTConst Art. 27, 61', 'Contrôle visuel quotidien', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000045', 'Contrôle de la solidité des clôtures devant empêcher l''accès au public. Vérification de la propreté de la piste d''accès et présence d''un dispositif de nettoyage des véhicules (décrotteur) pour éviter de souiller les chaussées.', NULL, 'RPAC Art. 7, 9 / Phase 5', 'Installations Générales (Clôtures et Accès)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000046', 'Vérification de la conformité du chantier aux dispositions relatives à la protection de l''environnement et des eaux, notamment l''installation et la propreté du bac de décantation de la centrale à béton.', NULL, 'RPAC Art. 14 / Phase 5', 'Protection de l''Environnement (Eaux)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000047', 'Contrôle de l''aménagement des fouilles, puits et terrassements pour éviter l''éboulement. Vérification de l''étayage ou du blindage obligatoire pour les fouilles de plus de 1,50 m de profondeur.', NULL, 'OTConst Art. 68, 77 / Phase 5', 'Sécurité des Fouilles (Étayage et Blindage)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000048', 'Contrôle des ponts métalliques et passerelles installés sur les fouilles. Si des différences de niveau de plus de 50 cm existent, des escaliers ou équipements sûrs doivent être mis en place. Les passerelles doivent avoir une solidité adaptée et être assurées contre le glissement.', NULL, 'OTConst Art. 13, 15 / Phase 5', 'Sécurité des Fouilles (Passerelles et Accès)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000049', 'Incitation et vérification stricte du port des EPI dès le début des travaux. Port obligatoire du casque de protection (et jugulaire selon les tâches) et de vêtements à haute visibilité à proximité des machines.', NULL, 'OTConst Art. 6, 7 / Phase 5', 'Équipements de Protection Individuelle (EPI)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000050', 'L''employeur doit avoir désigné sur le chantier une personne compétente chargée de la sécurité, capable de donner des directives. Tout travailleur s''exposant à un danger doit être renvoyé du chantier.', NULL, 'OTConst Art. 5 / RPAC Art. 3', 'Organisation et Personnes Compétentes', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000051', 'Au terme de la visite, confirmation que toutes les installations préliminaires permettent le commencement sécurisé des travaux.', NULL, 'Phase 5', 'Validation Globale du Démarrage (Go/No-Go)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000052', 'S''assurer en continu que les clôtures de protection du public restent conformes à l''évolution du chantier. Les cheminements publics (piétons, personnes handicapées) doivent être maintenus en toute sécurité et l''interdiction de pénétrer signalée.', NULL, 'Phase 6 / RPAC Art. 7', 'Suivi des Clôtures et Accès publics', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000053', 'Vérifier l''utilisation correcte des échafaudages au fur et à mesure de l''élévation. S''assurer particulièrement que les ancrages ne sont pas enlevés prématurément et que les charges utiles (affichées sur panneaux) ne sont pas dépassées.', NULL, 'Phase 6 / OTConst Art. 51, 61, 62 / RPAC Art. 18', 'Contrôle des Échafaudages (Ancrages et Surcharges)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000054', 'S''assurer que les trémies et ouvertures dans les sols qui présentent un risque de chute restent pourvues d''un garde-corps périphérique ou d''une couverture résistante et solidement fixée au fil de l''avancement des travaux.', NULL, 'Phase 6 / OTConst Art. 25', 'Sécurisation des Trémies et Bords de dalles', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000055', 'L''employeur doit veiller à ce que les filets de sécurité (et échafaudages de retenue) soient contrôlés visuellement chaque jour. S''ils présentent des défauts, leur utilisation est interdite.', NULL, 'Phase 6 / OTConst Art. 27', 'Contrôle des Filets de sécurité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000056', 'Rappeler et inviter les entreprises à respecter strictement le port des EPI. Le casque de protection (avec jugulaire selon les cas) et les vêtements à haute visibilité doivent être portés par tous les travailleurs exposés.', NULL, 'Phase 6 / OTConst Art. 6, 7', 'Équipements de Protection Individuelle (EPI)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000057', 'S''assurer que les déblais ne sont pas jetés librement mais évacués de manière à exclure la mise en danger ou les poussières excessives (ex: utilisation de dévaloirs fermés). Veiller à ne pas souiller les chaussées publiques.', NULL, 'RPAC Art. 9, 15 / Phase 6', 'Évacuation des Matériaux et Propreté', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000058', 'Les échafaudages, passages et ponts doivent être nettoyés et rendus non glissants (sablage/salage). Par grand vent, les machines doivent être amarrées et le travail poursuivi uniquement si la sécurité est assurée.', NULL, 'RPAC Art. 10', 'Protection contre les Intempéries (Vent/Neige)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000059', 'En cas de danger imminent ou de violation manifeste des règles de sécurité (ex: ancrages d''échafaudage retirés, absence d''EPI grave), inviter à faire cesser la menace immédiatement et aviser la SUVA.', NULL, 'Phase 6 / RPAC Art. 31', 'Gestion des Manquements et Avis SUVA', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000060', 'Contrôle de la bonne transition entre les protections provisoires de chantier et celles de l''état définitif. Cela inclut l''installation à demeure des barres de sécurité en toiture, des crochets pour cordes, et des dispositifs d''ancrage en façade pour l''entretien futur.', NULL, 'RPAC Art. 3, 23, 24 / Phase 7', 'Transition de sécurité (Provisoire à Définitif)', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000061', 'Si une partie du bâtiment neuf est déjà habitée ou accessible au public alors que le chantier se poursuit, il faut veiller à ce qu''une clôture dissuasive sépare strictement la zone habitée de la zone en chantier.', NULL, 'RPAC Art. 7 / Phase 7', 'Occupation partielle du bâtiment', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000062', 'Le démontage des échafaudages doit être effectué sous la direction d''une personne compétente et selon un ordre sécurisé. L''abattage et le démontage brutal d''échafaudages ou de leurs éléments sont strictement interdits.', NULL, 'RPAC Art. 17', 'Démontage des échafaudages', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000063', 'L''enlèvement des coffrages, des étais et des boisages divers doit se faire avec prudence. Les aspérités dangereuses telles que les clous et les vis saillants doivent être éliminées aussitôt le décoffrage effectué.', NULL, 'RPAC Art. 16', 'Décoffrage et élimination des dangers', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000064', 'Lors du nettoyage final, les déblais et gravats ne doivent pas être jetés librement depuis les étages. Ils doivent être dévalés (ex: via dévaloirs fermés) pour exclure toute mise en danger ou dégagement excessif de poussières.', NULL, 'RPAC Art. 15', 'Évacuation finale des gravats', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000065', 'Compilation des preuves que la sécurité a été maintenue tout au long de la construction et que l''ouvrage livré respecte les normes de sécurité publiques exigées par les organes de contrôle.', NULL, 'RPAC (Général)', 'Génération du Dossier Final (DOE)', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000066', 'Vérifier que les mesures de protection du public sont incluses dans les devis et que l''entreprise a désigné un responsable sécurité 2.', 'Obligatoire avant de débuter, responsable sécurité désigné nommément 2.', 'RPAC Art. 3', 'Planification & Sécurité', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000066', 'Contrôler si des dispenses aux mesures du règlement ont été accordées.', 'Doit faire l''objet d''une demande et d''une décision écrites 3.', 'RPAC Art. 4', 'Dispense', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000066', 'Vérifier l''envoi de l''avis d''ouverture et de montage à la commune.', '10 jours à l''avance au moins pour l''ouverture, les grues et échafaudages 4.', 'RPAC Art. 5', 'Annonces aux autorités', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000066', 'Contrôler la disponibilité des notes de calculs (métal, béton, bois) si exigées par l''autorité 5.', 'Doivent respecter les normes de la Confédération et de la SIA 5.', 'RPAC Art. 6', 'Calculs statiques', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000067', 'Vérifier la résistance de la clôture et la présence de panneaux d''interdiction au public 6.', 'Aménagements piétons obligatoires tenant compte des handicapés physiques et de la vue 6.', 'RPAC Art. 7', 'Clôtures et Signalisation', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000067', 'Contrôler la conformité des installations électriques 7.', 'Respect strict des prescriptions de l''ASE et du fournisseur de courant 7.', 'RPAC Art. 8', 'Installations électriques', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000067', 'Vérifier l''état de la chaussée et l''entreposage des matériaux 7.', 'Installation d''un dispositif de nettoyage (décrotteur) exigible par l''autorité 7.', 'RPAC Art. 9', 'Propreté chaussée & Dépôts', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000067', 'Vérifier l''état des passages (salage/sablage) et l''amarrage du matériel par grand vent 8, 9.', 'Passages rendus non glissants, machines amarrées selon les directives du constructeur 8.', 'RPAC Art. 10', 'Intempéries & Vent', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000067', 'Contrôler la surveillance des travaux à chaud et la recherche d''amiante 9.', 'Extincteur requis pour soudage/meulage. Contrôle post-travail si risque de feu couvant. Amiante à suspecter lors de rénovations 9.', 'RPAC Art. 11', 'Incendie & Amiante', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000068', 'S''assurer que les ouvriers connaissent leur obligation de signaler tout défaut des installations 10, 11.', 'Signalement immédiat au chef de toute défectuosité ou comportement dangereux 11.', 'RPAC Art. 12-13', 'Signalement des défauts', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000068', 'Contrôler le respect des normes environnementales et de protection des eaux 11.', 'Incinération de déchets de chantiers strictement interdite 11.', 'RPAC Art. 14', 'Environnement & Feu', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000068', 'Vérifier le mode d''évacuation des déblais et gravats depuis les étages 12.', 'Interdiction de les jeter librement ; utilisation de dévaloirs fermés exigée pour éviter la poussière 12.', 'RPAC Art. 15', 'Évacuation des gravats', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000068', 'Vérifier l''élimination des dangers post-décoffrage 12.', 'Les aspérités dangereuses (clous, vis) doivent être éliminées aussitôt le décoffrage effectué 12.', 'RPAC Art. 16', 'Décoffrage', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier l''habilitation du personnel effectuant le montage/démontage 13.', 'Montage sous direction d''une personne compétente. Abattage brutal strictement interdit 13.', 'RPAC Art. 17', 'Montage et Démontage', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Contrôler l''étanchéité et l''accessibilité des passages sous échafaudage 14.', 'Passages étanches (boue/liquides). Empêcher l''accès aux personnes étrangères au chantier 14.', 'RPAC Art. 18', 'Protection du public', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Mesurer les dimensions des plateaux de garde (auvents) au-dessus de la rue 14.', 'Inclinés à 45°, hauteur min 1.50 m, bord inférieur à min 4.50 m au-dessus de la chaussée. Sans vide avec la façade 14.', 'RPAC Art. 19', 'Auvents de protection', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier l''autorisation pour l''usage de nacelles ou ponts volants 15.', 'Autorisation spéciale exigée, délivrée uniquement si un échafaudage de pied est impossible 15.', 'RPAC Art. 20-21', 'Ponts volants & Nacelles', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Évaluer la pente du toit et la hauteur de chute pour exiger l''échafaudage 16.', 'Exigé si bas du toit ≥ 3m ET pente > 20% (métal/plastique) ou > 40% (tuile/ardoise) 16.', 'RPAC Art. 22', 'Échafaudages de toit', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Contrôler la pose de barres de sécurité et de crochets à demeure 17, 18.', 'Barres à 2 traverses, distante de min 14 cm du toit, crochets espacés de max 1.65 m 17. Crochet fermé requis pour chaque accès 18.', 'RPAC Art. 23', 'Barres de sécurité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Vérifier la présence de dispositifs d''ancrage pour l''entretien futur des façades 19.', 'Obligatoire pour les façades rideaux inaccessibles aux camions-nacelles 19.', 'RPAC Art. 24', 'Ancrages permanents', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000071', 'Contrôler les permis des grutiers et conducteurs d''engins de chantier 20.', 'Titulaires d''un permis reconnu ou d''une attestation provisoire exigés 20.', 'RPAC Art. 25', 'Permis de conduite', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000071', 'Vérifier l''espace libre, la mise en girouette et les autorisations de hauteur 21, 22.', '8 m libre au-dessus de la route. Giration libre sans charge à l''arrêt. Accord OFAC si grue > 60m ou > 25m près d''aérodrome 21, 22.', 'RPAC Art. 26', 'Règles Grues (Survol)', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000071', 'Vérifier l''autorisation de l''organe de contrôle 22.', 'Autorisés uniquement en l''absence d''autres moyens techniques raisonnables 22.', 'RPAC Art. 27', 'Hélicoptères', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000071', 'Vérifier l''autorisation pour les travaux sur cordes au-dessus du public 23.', 'Autorisés uniquement en l''absence d''autres moyens. Mesures spéciales exigibles 23.', 'RPAC Art. 28', 'Travaux acrobatiques', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000072', 'Procédure d''urgence', 'En cas de danger imminent pour les travailleurs, ordre de cesser la menace et avis immédiat à la SUVA 26.', 'RPAC Art. 31', 'Avis SUVA (Danger grave)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000073', 'Vérifier que chaque entrepreneur a contrôlé ses installations 28.', 'L''entrepreneur est responsable de s''assurer de la conformité avant tout travail, même s''il n''est pas propriétaire du matériel 28.', 'RPAC Art. 34', 'Conformité par l''entreprise', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000073', 'Contrôler la transmission de l''information en cas de sinistre 29.', 'Avis immédiat à la commune si dommage à un tiers, et annonce à la SUVA pour tout accident de chantier 29.', 'RPAC Art. 35', 'Annonce d''accidents', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000074', 'Vérifier que les mesures de sécurité et l''évaluation des dangers (ex: amiante) sont planifiées et intégrées dans les contrats d''entreprise.', 'Obligatoire avant le début des travaux 4-8.', 'OTConst Art. 3', 'Planification & Contrats', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000074', 'Vérifier la présence d''un Plan de Sécurité et de Protection de la Santé (PPSPS) écrit.', 'Doit inclure l''organisation des premiers secours 9.', 'OTConst Art. 4', 'PPSPS', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000074', 'Contrôler qu''une personne compétente en sécurité est désignée sur le chantier.', 'Doit pouvoir donner des directives. Renvoi de toute personne dangereuse 10.', 'OTConst Art. 5', 'Organisation sécurité', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000074', 'Contrôler le port du casque de protection (et de la jugulaire selon travaux).', 'Jugulaire requise pour travaux sur cordes, antichute et hélicoptère 10-13.', 'OTConst Art. 6', 'Casque de protection', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000074', 'Vérifier le port de vêtements fluo avec bandes rétroréfléchissantes.', 'Obligatoire près des machines, engins ou voies publiques 13.', 'OTConst Art. 7', 'Vêtements haute visibilité', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000074', 'S''assurer que les numéros d''urgence sont affichés et le sauvetage garanti.', 'Médecin, hôpital, ambulance, police, pompiers, hélicoptère 14.', 'OTConst Art. 8', 'Sauvetage & Urgences', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Vérifier que les postes de travail offrent la sécurité voulue avec des protections contre les chutes.', 'Pose de protections contre les chutes (Art. 22 à 29) 14, 15.', 'OTConst Art. 9', 'Accès sécurisés', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Contrôler que les fers d''armature et objets pointus sont protégés.', 'Fers saillants recourbés ou recouverts de protections 15.', 'OTConst Art. 10', 'Objets tranchants', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Mesurer la largeur des voies de circulation et contrôler les accès.', 'Voies d''accès : min. 1 m. Autres : min. 60 cm. Escaliers si > 5 marches 15, 16.', 'OTConst Art. 11', 'Largeur des passages', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Contrôler la présence de barrières ou de panneaux interdisant l''accès aux surfaces non résistantes.', 'Passage obligatoire sur passerelles avec garde-corps des deux côtés 17, 18.', 'OTConst Art. 12', 'Surfaces fragiles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'S''assurer de la solidité des passerelles.', 'Doivent être assurées contre le glissement 18.', 'OTConst Art. 13', 'Passerelles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Mesurer l''espace libre entre les installations en mouvement et les obstacles.', 'Espace libre exigé : 0,5 m de large et 2,5 m de haut. Sinon, barricader 18, 19.', 'OTConst Art. 14', 'Pièces en mouvement', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Vérifier le moyen d''accès en cas de dénivelé.', 'Escaliers ou équipements sûrs obligatoires si dénivelé > 50 cm 19.', 'OTConst Art. 15', 'Différences de niveau', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Contrôler la solidité des ponts, bermes et digues.', 'Justificatif d''ingénieur requis. Distance bordure : min. 1 m 19-21.', 'OTConst Art. 16', 'Voies de circulation', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Vérifier les protections contre la chute ou l''écroulement d''éléments.', 'Pas de danger pour les postes et passages en dessous 22.', 'OTConst Art. 17', 'Écroulement / Chutes', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Contrôler le mode d''évacuation des gravats et matériels depuis la hauteur.', 'Zone barricadée ou utilisation de glissières/canaux fermés 22.', 'OTConst Art. 18', 'Jet de matériel', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000075', 'Vérifier l''absence de personnes dans la zone de danger des machines.', 'Utilisation de caméras, miroirs ou d''un signaleur. Marche arrière limitée 23, 24.', 'OTConst Art. 19', 'Engins de chantier', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000076', 'Contrôler l''état, la surface d''appui et le type d''échelle utilisé.', 'Échelons supérieurs interdits (3 pour simples, 2 pour doubles) 24, 25.', 'OTConst Art. 20', 'Conformité échelles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000076', 'Vérifier que l''utilisation de l''échelle portable est justifiée.', 'Si chute > 2 m, travaux de courte durée et protection antichute exigés 25, 26.', 'OTConst Art. 21', 'Travaux sur échelles', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Mesurer les dimensions des garde-corps périphériques (Lisse, plinthe).', 'Lisse haute à min. 100 cm, plinthe 15 cm. Écart max : 47 cm 26, 27.', 'OTConst Art. 22', 'Garde-corps (Conception)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Contrôler la présence de garde-corps selon la hauteur et l''environnement.', 'Obligatoire si chute > 2 m, talus > 2 m (pente > 45°), ou près de l''eau 28.', 'OTConst Art. 23', 'Garde-corps (Usage)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Vérifier les protections à l''intérieur du bâtiment.', 'Garde-corps (1 lisse haute min.) requis si dénivelé > 50 cm 29.', 'OTConst Art. 24', 'Dénivelé intérieur', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Contrôler la protection des ouvertures dans les sols.', 'Couverture résistante solidement fixée ou garde-corps 29.', 'OTConst Art. 25', 'Trémies / Ouvertures', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Vérifier le montage des échafaudages lors de la construction de bâtiments.', 'Requis dès 3 m de chute. Garde-corps doit dépasser la zone de 80 cm 30.', 'OTConst Art. 26', 'Échafaudage de façade', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Contrôler visuellement l''état des filets de sécurité.', 'Utilisation pour chute > 3 m. Contrôle visuel quotidien obligatoire 31.', 'OTConst Art. 27', 'Filets et Retenue', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Vérifier la fixation avant l''accès.', 'Accès autorisé uniquement si les éléments sont fixés 32.', 'OTConst Art. 28', 'Éléments préfabriqués', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000077', 'Contrôler les justificatifs si un garde-corps ou échafaudage est impossible.', 'Mesures doivent être fixées par écrit par un spécialiste de la sécurité 32, 33.', 'OTConst Art. 29', 'Mesures équivalentes', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000078', 'Vérifier le repérage de réseaux dangereux avant les travaux (gaz, élec).', 'Mesures fixées par écrit avec le propriétaire. Interruption si découverte 33, 34.', 'OTConst Art. 30', 'Installations existantes', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000078', 'Contrôler les coffrets électriques de chantier.', 'Prises ≤ 32 A protégées par disjoncteur différentiel 30 mA 35, 36.', 'OTConst Art. 31', 'Électricité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'Vérifier l''information aux travailleurs si présence d''amiante suspectée.', 'Interruption immédiate et information du maître d''ouvrage si trouvée 36, 37.', 'OTConst Art. 32', 'Polluants (Amiante/PCB)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'Contrôler l''air ambiant dans les espaces confinés/souterrains.', 'Entre 19% et 21% d''O2. Contrôle régulier. Appareils respi si besoin 37-39.', 'OTConst Art. 33', 'Qualité de l''air', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'Vérifier la présence d''extincteurs et les voies d''évacuation.', 'Barricade et panneau triangulaire requis pour les zones à risque d''explosion 40, 41.', 'OTConst Art. 34', 'Incendie / Explosion', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'Contrôler la présence d''EPI et de sauvetage près de l''eau.', 'Gilets de sauvetage, bouées, bateaux (pour eaux courantes) 41-43.', 'OTConst Art. 35', 'Risque de noyade', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'Contrôler le port des protections auditives.', 'Port obligatoire si la valeur limite d''exposition est dépassée 43.', 'OTConst Art. 36', 'Bruit', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'S''assurer de la protection contre les conditions climatiques extrêmes.', 'Mesures contre le soleil, la forte chaleur et le froid 44.', 'OTConst Art. 37', 'Climat', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'Vérifier le niveau d''éclairage des accès et postes de travail.', 'Doit être "suffisant" 44.', 'OTConst Art. 38', 'Éclairage', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000079', 'Vérifier les mesures (avalanches, chutes de pierres).', 'Surveillance, alerte secours et transport garantis. Zone évacuée si danger 44, 45.', 'OTConst Art. 39', 'Dangers naturels', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000080', 'Contrôler la sécurité sous les monte-charges et installations de transport.', 'Zone barricadée ou surveillée. Transport humain que si prévu par le fabricant 46, 47.', 'OTConst Art. 40', 'Transport levage', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Contrôler la présence du pont de ferblantier ou échafaudage selon la pente.', 'Pente 10-60°: pont ferblantier. >60°: nacelle ou échafaudage 48-51.', 'OTConst Art. 41', 'Mesures bords de toits', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Contrôler les dimensions de la paroi pour les toits existants (≤45°).', 'Hauteur 100 cm min, dépassement de 80 cm au-dessus du chéneau 51, 52.', 'OTConst Art. 42', 'Paroi de retenue toits', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Mesurer l''espace entre le pont de ferblantier et la façade.', 'Ne doit pas dépasser 30 cm 52, 53.', 'OTConst Art. 43', 'Distance pont/façade', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Vérifier la preuve de résistance de la toiture avant accès.', 'Si pas de preuve = non résistant. Protections exigées pour les ouvertures 53.', 'OTConst Art. 44', 'Solidité toitures', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Contrôler les accès sur les toits fragiles (ex: fibrociment).', 'Passerelles obligatoires, ou filets/retenue si chute > 3 m 54, 55.', 'OTConst Art. 45', 'Toits non résistants', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000070', 'Vérifier les mesures pour travaux très courts (< 2 jours-personne).', 'Chute > 3 m = EPI antichute obligatoires 55, 56.', 'OTConst Art. 46', 'Travaux de peu d''ampleur', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier que l''échafaudage est conçu selon la Loi sur la sécurité des produits.', 'Doit résister au vent, neige, poids et forces dynamiques 56, 57.', 'OTConst Art. 47', 'Capacité de charge', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Contrôler visuellement l''état des éléments tubulaires.', 'Composants courbés, pliés ou corrodés interdits 57.', 'OTConst Art. 48', 'Pièces endommagées', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier les appuis de l''échafaudage au sol.', 'Repos sur surfaces résistantes, assuré contre le glissement 58.', 'OTConst Art. 49', 'Fondations', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Contrôler le verrouillage des composants.', 'Assurés contre tout déplacement involontaire 58.', 'OTConst Art. 50', 'Stabilité', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier les points de fixation à la façade.', 'Posés au fur et à mesure du montage pour résister à la traction/compression 58, 59.', 'OTConst Art. 51', 'Ancrages', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Contrôler les ajouts (treuils, panneaux publicitaires, bâches).', 'Validation et autorisation de l''entrepreneur en échafaudage requise 59, 60.', 'OTConst Art. 52', 'Éléments annexés', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier le matériau des montants porteurs de façade.', 'Perches verticales porteuses en bois strictement interdites 60.', 'OTConst Art. 53-54', 'Conception générale', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Mesurer la largeur du platelage et vérifier la classe de charge.', 'Léger (peinture) = 60 cm (2.0 kN/m²). Lourd (maçonnerie) = 90 cm (3.0 kN/m²) 60-62.', 'OTConst Art. 55', 'Charge & Largeur', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier les moyens d''accès aux ponts (escaliers).', 'Distance max 25m avec chaque poste. Ascenseur requis si hauteur > 25 m 62-64.', 'OTConst Art. 56', 'Accès', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Mesurer la hauteur entre les ponts et la distance au mur.', 'Hauteur : 1,9 m à 2,3 m. Distance platelage/façade : max 30 cm 64, 65.', 'OTConst Art. 57', 'Espacement pont/façade', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Mesurer la position du pont par rapport au bord du toit.', 'Placé 1 m max en dessous du bord du toit. Lisse à 80 cm au-dessus du toit 65, 66.', 'OTConst Art. 58', 'Pont de ferblantier', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier le maillage de la paroi de protection.', 'Ouvertures dans la paroi ne doivent pas dépasser 100 cm² 66, 67.', 'OTConst Art. 59', 'Paroi couvreur', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Contrôler la procédure de montage.', 'Doit suivre les prescriptions du fabricant 67.', 'OTConst Art. 60', 'Montage / Démontage', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier que l''état de l''échafaudage est validé quotidiennement.', 'Gravats, neige et glace doivent être évacués des accès 67, 68.', 'OTConst Art. 61', 'Contrôle visuel quotidien', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier la présence des panneaux d''indication de charge.', 'Obligatoire à chaque accès, bien visible 68.', 'OTConst Art. 62', 'Affichage charge utile', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Contrôler les zones non autorisées d''utilisation.', 'Barricadées physiquement (ex: garde-corps périphérique) 68, 69.', 'OTConst Art. 63', 'Blocage accès', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier qui a altéré l''échafaudage.', 'Exclusivement par/avec accord écrit de l''entrepreneur en échafaudages 69.', 'OTConst Art. 64', 'Modifications', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Contrôler la stabilité et les roues des tours mobiles.', 'Hauteur max du fabricant. Déplacement interdit si un humain est dessus 69, 70.', 'OTConst Art. 65', 'Échafaudages roulants', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier le dispositif antichute en porte-à-faux.', 'Chute max 2 m. Portée horizontale d''au moins 1,5 m 71, 72.', 'OTConst Art. 66', 'Échaf. de retenue', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000069', 'Vérifier la hauteur de pose des filets de protection.', 'Posés pour éviter une chute > 3 m 72.', 'OTConst Art. 67', 'Filets de sécurité', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Mesurer la profondeur de la tranchée.', 'Étayage, blindage ou talutage obligatoire dès 1,50 m de profondeur 72.', 'OTConst Art. 68', 'Blindage obligatoire', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Mesurer l''espace de travail dans la tranchée.', 'Min 60 cm pour conduite ≤ 40 cm. Varie avec le diamètre du tuyau 73, 74.', 'OTConst Art. 69', 'Largeur utile fouilles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Mesurer la largeur de travail dans les grands terrassements.', 'Min 60 cm pour toutes les phases de travail 75.', 'OTConst Art. 70', 'Espace terrassements', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Vérifier la zone sans charge au bord de l''excavation.', 'Bord libre de 50 cm (si blindé) ou 1 m (si paroi talutée) 75, 76.', 'OTConst Art. 71', 'Bords libres de fouille', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Contrôler les tas de déblais près de la zone.', 'Ne doivent mettre aucun travailleur en danger (glissement) 76.', 'OTConst Art. 72', 'Dépôts de matériaux', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Vérifier les moyens de descente dans la tranchée.', 'Escaliers avec paliers tous les 5 m max (échelles tolérées jusqu''à 5 m) 76, 77.', 'OTConst Art. 73', 'Accès aux fouilles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Vérifier la circulation des véhicules autour de la fosse.', 'Bouteroues, signaux ou limitations de vitesse requis 77, 78.', 'OTConst Art. 74', 'Sécurité circulation bords', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Évaluer la pente du terrain.', 'Adaptée au terrain, sécurisée après forte pluie ou dégel 78.', 'OTConst Art. 75', 'Résistance du talus', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Contrôler la présence du justificatif d''un ingénieur spécialisé.', 'Exigé si hauteur > 4 m, charges lourdes, ou présence de nappe phréatique 78-80.', 'OTConst Art. 76', 'Justificatif géotechnique', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Vérifier la résistance des blindages.', 'Doit tenir compte des charges de véhicules et engins de chantier 80.', 'OTConst Art. 77', 'Blindages (charges)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Contrôler l''espace entre le fond/parois et le blindage.', 'Paroi max 80 cm sans étai (bas). Espaces vides derrière parois max 20 cm 81, 82.', 'OTConst Art. 78', 'Exécution du blindage', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Vérifier l''approbation d''un ingénieur spécialisé.', 'Justificatif requis pour injection, congélation, gunitage 82, 83.', 'OTConst Art. 79', 'Consolidation terrain', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000081', 'Contrôler le bord des parois.', 'Purge immédiate des roches, souches, blocs erratiques 84.', 'OTConst Art. 80', 'Matériaux en surplomb', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000082', 'Contrôler les mesures spéciales du PPSPS pour la déconstruction.', 'Empêcher l''écroulement inopiné, surveillance permanente par un expert 85, 86.', 'OTConst Art. 81', 'Démolition sécurisée', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000083', 'Vérifier l''agrément de l''entreprise si fibrociment/amiante.', 'Désamiantage obligatoire par entreprise reconnue par la SUVA 86-88.', 'OTConst Art. 82', 'Entreprise reconnue', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000083', 'Contrôler les qualifications du personnel.', 'Présence continue d''un spécialiste amiante et de 2 travailleurs instruits 88-91.', 'OTConst Art. 83-84', 'Spécialiste amiante', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000083', 'Vérifier le registre de formation du spécialiste.', 'Formation continue requise tous les 5 ans 91.', 'OTConst Art. 85', 'Formation amiante', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000083', 'Contrôler la date d''annonce des travaux de désamiantage.', 'Obligatoire auprès de la SUVA 14 jours avant exécution 92.', 'OTConst Art. 86', 'Annonce SUVA', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Contrôler la date d''annonce des travaux souterrains.', 'Obligatoire auprès de la SUVA 14 jours avant exécution 92, 93.', 'OTConst Art. 87', 'Annonce SUVA', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier les alimentations de secours.', 'Requis pour l''aération, les pompes, l''éclairage, l''avertisseur gaz 93, 94.', 'OTConst Art. 88-89', 'Énergie redondante', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'S''assurer de la protection des ouvriers (chaleur/humidité).', 'Mesures appropriées selon le climat souterrain 94.', 'OTConst Art. 90', 'Conditions climatiques', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier le concept de ventilation et de qualité de l''air.', 'Espaces ventilés obligatoires, ou mesure permanente de l''air exigée 95.', 'OTConst Art. 91', 'Ventilation continue', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier la détection des gaz (grisou/radon).', 'Mesures si couches rocheuses contiennent du gaz naturel 95.', 'OTConst Art. 92', 'Gaz naturel', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Contrôler le type de motorisation des engins dans le tunnel.', 'Moteurs essence/gaz liquide strictement interdits dans les souterrains 96.', 'OTConst Art. 93', 'Moteurs à combustion', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier l''éclairage de secours.', 'Éclairage de secours central ou lampe individuelle par travailleur requis 96.', 'OTConst Art. 94', 'Éclairage tunnel', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Contrôler les mesures lors de rénovation de tunnel sous trafic.', 'Séparation physique protégeant les travailleurs du flux 96.', 'OTConst Art. 95', 'Trafic routier/ferré', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier la visibilité des conducteurs d''engins souterrains.', 'Visibilité permanente de la zone de danger dans le sens de marche 97, 98.', 'OTConst Art. 96', 'Engins de transport', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier la protection des gaines d''aération.', 'Tuyaux d''amenée d''air frais protégés contre les dommages physiques 98.', 'OTConst Art. 97', 'Protection des installations', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Contrôler la séparation entre piétons et voies ferrées souterraines.', 'Séparation par des mesures techniques obligatoires 99.', 'OTConst Art. 98', 'Cheminements piétons', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier les sondages préalables à l''excavation.', 'Sondage d''éboulement ou de venue d''eau avant excavation 99, 100.', 'OTConst Art. 99', 'Sondages / Effondrement', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier le respect de la temporisation post-tir.', 'Reprise des travaux autorisée au plus tôt 15 minutes après l''explosion. Purge obligatoire 100, 101.', 'OTConst Art. 100', 'Minage (Tir à l''explosif)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000084', 'Vérifier le port d''EPI haute visibilité dans le tunnel.', 'Doit couvrir "toutes les parties du corps" 101.', 'OTConst Art. 101', 'Vêtements signalisation', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000085', 'Contrôler l''obligation d''annonce pour les carrières et terrassements.', 'Obligatoire si abattage rocheux > 5000 m³ (14 jours avant) 102.', 'OTConst Art. 102', 'Annonce SUVA', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000085', 'Vérifier la pente de la découverte (front de taille).', 'Pente max 45°. Distance min de 1 m entre le pied et l''angle 102, 103.', 'OTConst Art. 103-104', 'Inclinaison talus', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000085', 'Contrôler la hauteur des gradins.', 'Subdivisé en gradins, hauteur max 40 m. Évaluation de stabilité après tir 103, 104.', 'OTConst Art. 105', 'Abattage à l''explosif', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000085', 'Vérifier la hauteur du front de taille.', 'Extraction depuis le bas limitée à la hauteur d''atteinte de la machine 105.', 'OTConst Art. 106', 'Extraction', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000085', 'Contrôler la sécurisation du personnel sur terrain escarpé.', 'Sape interdite. Assurage encordé obligatoire (art. 22-29) 106.', 'OTConst Art. 107-108', 'Sape et chute de hauteur', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000085', 'Vérifier la protection des cabines de machines.', 'Cabines de conduite équipées de grilles anti-chutes de pierres 106, 107.', 'OTConst Art. 109', 'Éboulement', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000085', 'Contrôler la purge de la paroi.', 'Après intempéries, purge obligatoire des surplombs et matériaux instables 107, 108.', 'OTConst Art. 110', 'Reprise après arrêt', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000086', 'Vérifier la présence d''une personne instruite.', 'Au moins 1 personne formée présente en permanence sur place 108-110.', 'OTConst Art. 111-112', 'Qualifications', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000086', 'Vérifier le verrouillage mécanique/électrique des brûleurs.', 'Cadenas posé, fiche électrique débranchée, panneau de signalisation affiché 110, 111.', 'OTConst Art. 113', 'Consignation (LOTO)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000086', 'Vérifier le refroidissement et l''absence de gaz (mesure).', 'Mesure préalable des gaz requise, ou appareil respiratoire indépendant 112, 113.', 'OTConst Art. 114', 'Gaz nocifs et Chaudières', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000086', 'Contrôler les échelles d''accès fixes.', 'Nacelle ou filet/EPI antichute si échelle fixe absente 113-115.', 'OTConst Art. 115-116', 'Ascension de cheminées', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000086', 'Vérifier la présence de potelets électriques en toiture.', 'Lignes isolées, séparées de l''arrivée de courant ou protégées du contact 115, 116.', 'OTConst Art. 117', 'Raccordements élec.', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000087', 'Contrôler l''équipement et les binômes.', '2 travailleurs min (surveillance). 2 cordes ancrées séparément. Formation 116, 117.', 'OTConst Art. 118', 'Travaux encordés', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000088', 'Mesurer l''espace utile et vérifier la surveillance.', 'Surveillant externe permanent. Si < 600 mm : travaux exclusifs par robots 117-119.', 'OTConst Art. 119', 'Travail en conduites', false, true)
